/**
 * transport-selector.test.ts — verify URL scheme dispatch.
 *
 * Strategy: inject stub factories so the test never touches real sockets,
 * fetch, or DNS. Each stub returns a tagged sentinel with the args it was
 * called with; the test asserts the right factory ran with the right slice
 * of the URL.
 */

import { describe, expect, it } from 'vitest';
import { openStation, type TransportFactories } from './transport-selector';
import type { IStation } from './types';

interface TaggedStation extends IStation {
  __tag: string;
  __args: Record<string, unknown>;
}

function makeFakeFactories(): TransportFactories {
  const fake = (tag: string) =>
    (...args: unknown[]): TaggedStation => {
      return {
        __tag: tag,
        __args: { args },
        startLayer: 0,
        endLayer: 0,
        role: undefined,
        forward: () => {
          throw new Error('stub');
        },
        embed: () => {
          throw new Error('stub');
        },
        lmHead: () => {
          throw new Error('stub');
        },
        cobordismEmbed: () => {
          throw new Error('stub');
        },
        cobordismLmHead: () => {
          throw new Error('stub');
        },
        bizarroForward: async () => null,
      } as unknown as TaggedStation;
    };
  return {
    http: fake('http') as TransportFactories['http'],
    uds: fake('uds') as TransportFactories['uds'],
    flowUds: fake('flowUds') as TransportFactories['flowUds'],
    flowUdp: fake('flowUdp') as TransportFactories['flowUdp'],
    ws: fake('ws') as TransportFactories['ws'],
  };
}

describe('openStation URL scheme dispatch', () => {
  it('routes http:// URLs to the HTTP Station factory', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'http://layer-node-3.example.com/forward',
      layerRange: [0, 8],
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('http');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('http://layer-node-3.example.com/forward');
    expect(args[1]).toEqual([0, 8]);
  });

  it('routes https:// URLs to the HTTP Station factory', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'https://layer-node-3.example.com/forward',
      layerRange: [0, 8],
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('http');
  });

  it('routes unix:// URLs to the UDS Station factory and strips the prefix', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'unix:///tmp/fat-station.sock',
      layerRange: [8, 16],
      role: 'mid',
      timeoutMs: 5000,
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('uds');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('/tmp/fat-station.sock');
    expect(args[1]).toEqual([8, 16]);
    expect(args[2]).toBe('mid');
    expect(args[3]).toBe(5000);
  });

  it('routes bare /absolute/path to the UDS Station factory (legacy)', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: '/tmp/fat-station.sock',
      layerRange: [8, 16],
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('uds');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('/tmp/fat-station.sock');
  });

  it('routes flow+unix:// URLs to the StationFlow factory', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'flow+unix:///tmp/fat-station-flow.sock',
      layerRange: [16, 24],
      role: 'exit',
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('flowUds');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('/tmp/fat-station-flow.sock');
    expect(args[1]).toEqual([16, 24]);
    expect(args[2]).toBe('exit');
  });

  it('routes flow+udp://host:port URLs to the StationFlowUdp factory', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'flow+udp://127.0.0.1:9300',
      layerRange: [0, 8],
      role: 'entry',
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('flowUdp');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('127.0.0.1');
    expect(args[1]).toBe(9300);
    expect(args[2]).toEqual([0, 8]);
    expect(args[3]).toBe('entry');
  });

  it('rejects unknown schemes', () => {
    const factories = makeFakeFactories();
    expect(() =>
      openStation({
        url: 'gopher://nope',
        layerRange: [0, 8],
        factories,
      }),
    ).toThrow(/unrecognized URL scheme/);
  });

  it('rejects flow+udp:// without a port', () => {
    const factories = makeFakeFactories();
    expect(() =>
      openStation({
        url: 'flow+udp://localhost',
        layerRange: [0, 8],
        factories,
      }),
    ).toThrow(/host:port/);
  });

  it('routes ws+https:// URLs to the WSStation factory and strips the prefix', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'ws+https://tri-g4-a-00.taylorbuley.workers.dev',
      layerRange: [0, 1],
      role: 'mid',
      wsPhase: 'split-a',
      wsBearerToken: 'mesh-bench',
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('ws');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('https://tri-g4-a-00.taylorbuley.workers.dev');
    expect(args[1]).toEqual([0, 1]);
    expect(args[2]).toBe('mid');
    expect(args[3]).toBe('split-a');
    expect(args[4]).toBe('mesh-bench');
  });

  it('routes ws+http:// URLs to the WSStation factory (insecure)', () => {
    const factories = makeFakeFactories();
    const station = openStation({
      url: 'ws+http://localhost:8787',
      layerRange: [4, 5],
      wsPhase: 'split-c',
      factories,
    }) as TaggedStation;
    expect(station.__tag).toBe('ws');
    const args = (station.__args as { args: unknown[] }).args;
    expect(args[0]).toBe('http://localhost:8787');
    expect(args[3]).toBe('split-c');
  });

  it('rejects ws+https:// without wsPhase', () => {
    const factories = makeFakeFactories();
    expect(() =>
      openStation({
        url: 'ws+https://tri-g4-a-00.taylorbuley.workers.dev',
        layerRange: [0, 1],
        factories,
      }),
    ).toThrow(/wsPhase/);
  });

  it('rejects empty unix:// path', () => {
    const factories = makeFakeFactories();
    expect(() =>
      openStation({
        url: 'unix://',
        layerRange: [0, 8],
        factories,
      }),
    ).toThrow(/socket path/);
  });
});
